#include <stdlib.h>
#include <stdio.h>

const int MOD = 1000000007;

int main(void) {
   int n, k, d, ans, i, j;
   scanf("%d%d%d", &n, &k, &d);
   int memW[n + 1];
   int memWO[n + 1];
   for (i = 0; i <= n; i++)
      memW[i] = (memWO[i] = 0);
   memW[0] = (memWO[0] = 1);
   for (i = 0; i < n; i++)
      for (j = 1; j + i <= n && j <= k; j++){
         memW[j + i] += memW[i];
         if (memW[i + j] >= MOD)
            memW[i + j] -= MOD;
         if (j < d){
            memWO[j + i] += memWO[i];
            if (memWO[i + j] >= MOD)
               memWO[i + j] -= MOD;
         }
      }
   ans = memW[n] - memWO[n];
   if (ans < 0)
      ans += MOD;
   printf("%d\n", ans);
   return 0;
}

