    dp[0][0] += 1;

    for i in 1..=n {
        for j in 1..=k {
            if i < j {
                continue;
            }
            if j < d {
                dp[i][0] = dp[i][0] + dp[i - j][0];
                dp[i][1] = dp[i][1] + dp[i - j][1];
            } else {
                dp[i][1] = dp[i][1] + dp[i - j][0];
                dp[i][1] = dp[i][1] + dp[i - j][1];
            }
        }
    }
    println!("{}", dp[n][1].0);
